```
Always replace the array reference entirely using the spread operator: `this.array = [...this.array, newItem]`. Mutating the array with `.push()` does not trigger reactivity because the array reference stays the same. Glimmer only detects the change when `this.batsmen` is assigned a new value.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class PlayerListComponent extends Component {
  @tracked players = ['Tamim', 'Liton', 'Shakib', 'Mushfiq'];

