`{{#each}}` iterates over the `@tracked` array and re-renders the list whenever the array reference changes. Always replace the array (not mutate) to trigger the update. Use `as |item|` to access each element, and optionally `as |item index|` to get the index.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

// Child component
class ScoreButtonComponent extends Component {
  <template>
    <button {{on "click" @onScore}} class="btn-primary">
      +{{@runsValue}} Runs
    </button>
  </template>
}

// Parent component
export default class MatchControlComponent extends Component {
  @tracked totalRuns = 0;

  @action
  addRuns(runs) {
    this.totalRuns = this.totalRuns + runs;
  }

  <template>
