import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class PlayerSearchListComponent extends Component {
  @tracked allPlayers = [
    'Tamim Iqbal', 'Shakib Al Hasan', 'Mushfiqur Rahim',
    'Liton Das', 'Mehidy Hasan', 'Taskin Ahmed',
  ];
  @tracked query = '';

  get filteredPlayers() {
    const q = this.query.toLowerCase().trim();
    if (!q) return this.allPlayers;
    return this.allPlayers.filter(name => name.toLowerCase().includes(q));
