```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class OversLimitComponent extends Component {
  @tracked _maxOvers = 20;
  @tracked validationError = '';

  get maxOvers() {
    return this._maxOvers;
  }

  set maxOvers(value) {
    const parsed = Number(value);
    if (!Number.isInteger(parsed) || parsed < 1 || parsed > 50) {
      this.validationError = 'Overs must be a whole number between 1 and 50';
      return;
    }
    this.validationError = '';
    this._maxOvers = parsed;
  }

