```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class MatchAnalyticsComponent extends Component {
  @tracked runs = 180;
  @tracked balls = 120;
  @tracked wickets = 4;

  get strikeRate() {
    if (this.balls === 0) return 0;
    return (this.runs / this.balls) * 100;
  }

  get strikeRateLabel() {
    const sr = this.strikeRate;
    if (sr >= 150) return 'Explosive';
    if (sr >= 100) return 'Good';
    if (sr >= 70) return 'Steady';
    return 'Slow';
  }

