```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchListComponent extends Component {
  @tracked isLoading = false;
  @tracked matches = [];
  @tracked error = null;

  @action
  async loadMatches() {
    this.isLoading = true;
    this.error = null;
    try {
      const response = await fetch('/api/matches');
      this.matches = await response.json();
    } catch (err) {
      this.error = err.message;
    } finally {
      this.isLoading = false;
    }
  }

  <template>
    <button {{on "click" this.loadMatches}} disabled={{this.isLoading}}>
      {{if this.isLoading 'Loading...' 'Load Matches'}}
    </button>
    {{#if this.error}}
      <p class="text-red-600">{{this.error}}</p>
    {{/if}}
    {{#each this.matches as |match|}}
      <p>{{match.name}}</p>
    {{/each}}
  </template>
}
```
The trio of `isLoading`, `matches`, and `error` covers the three states of an async operation: pending, success, and failure. Using `finally` ensures `isLoading` is always reset even if the fetch throws. All three `@tracked` properties update within the same async action, but Glimmer batches synchronous updates.

