import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchPaginationComponent extends Component {
  @tracked currentPage = 1;
  pageSize = 10;

  get totalPages() {
    return Math.ceil((this.args.totalMatches ?? 0) / this.pageSize);
  }

  get isFirstPage() { return this.currentPage === 1; }
  get isLastPage() { return this.currentPage >= this.totalPages; }

  @action
  prevPage() {
    if (!this.isFirstPage) this.currentPage = this.currentPage - 1;
  }

  @action
  nextPage() {
    if (!this.isLastPage) this.currentPage = this.currentPage + 1;
  }

  <template>
    <div class="flex items-center gap-3">
      <button {{on "click" this.prevPage}} disabled={{this.isFirstPage}}>Prev</button>
      <span>Page {{this.currentPage}} of {{this.totalPages}}</span>
      <button {{on "click" this.nextPage}} disabled={{this.isLastPage}}>Next</button>
    </div>
  </template>
}
```
Use a `@tracked` number for the current page and compute `totalPages` as a getter from `@args`. Guard boundary actions with boolean getters. `pageSize` is a plain (non-tracked) property since it never changes at runtime.

