        <p class="text-red-700">{{this.apiError.message}}</p>
        <p class="text-xs text-red-400">Status: {{this.apiError.status}}</p>
      </div>
    {{/if}}
    {{#if this.player}}
      <p>{{this.player.name}}</p>
    {{/if}}
  </template>
}
