  get sortedPlayers() {
    return [...(this.args.players ?? [])].sort((a, b) => {
      const mul = this.sortDir === 'desc' ? -1 : 1;
      return mul * (a[this.sortColumn] - b[this.sortColumn]);
    });
  }

  <template>
    <table>
      <thead><tr>
        <th><button {{on "click" (fn this.sortBy 'runs')}}>Runs {{this.columnIcon 'runs'}}</button></th>
        <th><button {{on "click" (fn this.sortBy 'average')}}>Avg {{this.columnIcon 'average'}}</button></th>
