import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class PlayerPins extends Component {
  @tracked pinnedIds = [];

  get pinnedSet() {
    return new Set(this.pinnedIds);
  }

  @action
  pinPlayer(playerId) {
    if (!this.pinnedSet.has(playerId)) {
      this.pinnedIds = [...this.pinnedIds, playerId];
    }
  }

  @action
  unpinPlayer(playerId) {
    this.pinnedIds = this.pinnedIds.filter(id => id !== playerId);
  }

  <template>
    {{#each @players as |player|}}
      <div class="flex items-center gap-2">
        <span>{{player.name}}</span>
        <button type="button" {{on "click" (fn this.pinPlayer player.id)}} class="text-xs">
          {{if (this.pinnedSet.has player.id) '📌 Pinned' 'Pin'}}
        </button>
      </div>
    {{/each}}
  </template>
}
