// service/match-store.js
import Service from '@ember/service';
import { tracked } from '@glimmer/tracking';

export default class MatchStoreService extends Service {
  @tracked currentMatchId = null; // ONE instance, shared by all components
  @tracked liveScore = 0;        // All components injecting this service
}                                // see the same value

// COMPONENT: local to one rendered instance
