import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class NoShouldUpdate extends Component {
  @tracked score = 0;

  // Glimmer does NOT need shouldComponentUpdate because:
  // 1. Only expressions that READ a changed @tracked value re-render
  // 2. Expressions that didn't read the changed tag are untouched
  // 3. Memoized getters only re-compute when their specific dependencies change

  get scoreDisplay() {
    return `Score: ${this.score}`;
  }

  // unrelatedData is a plain property — reading it in a template expression
  // creates NO tracked dependency — changes to it don't trigger re-renders
  unrelatedData = 'static';

  <template>
    {{!-- Only re-renders when 'score' changes --}}
    <p>{{this.scoreDisplay}}</p>
    {{!-- Never re-renders (no tracked dependency) --}}
    <p>{{this.unrelatedData}}</p>
  </template>
