import { action } from '@ember/object';

export default class PlayerRosterComponent extends Component {
  @tracked searchQuery = '';

  // ❌ Avoid — storing derived value in @tracked requires manual sync
  // @tracked filteredPlayers = [];
  // @action search(e) { this.searchQuery = e.target.value; this.filteredPlayers = ...; }

  // ✅ Getter — always in sync, no manual update needed
  get filteredPlayers() {
    const q = this.searchQuery.toLowerCase();
    return this.args.players.filter(p => p.name.toLowerCase().includes(q));
  }

  // ✅ @cached getter — if player list is very large (500+ items)
  @cached
  get filteredPlayersCached() {
    const q = this.searchQuery.toLowerCase();
    return this.args.players.filter(p => p.name.toLowerCase().includes(q));
  }

  @action onSearch(e) { this.searchQuery = e.target.value; }

