Never store derived data in `@tracked`. A getter is always derived from its dependencies — it cannot be stale. Storing derived data in `@tracked` creates a synchronization obligation: every code path that changes source data must also update the derived `@tracked`, and missing one causes silent UI bugs. For expensive filtering on large lists, add `@cached` to the getter instead of promoting to `@tracked`. The `@cached` approach gives memoization without synchronization burden.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

// Option A — @tracked error string (simple cases)
class OptionAComponent extends Component {
  @tracked errorMessage = '';
  get hasError() { return this.errorMessage.length > 0; }
}

// Option B — @tracked Error object (✅ Recommended for API operations)
export default class MatchFormComponent extends Component {
  @tracked error = null;

  get hasError() { return this.error !== null; }
  get errorMessage() { return this.error?.message ?? ''; }
  get errorCode() { return this.error?.code ?? null; }

  @action
  async submitScore(scoreData) {
    this.error = null;
    try {
      await fetch('/api/scores', { method: 'POST', body: JSON.stringify(scoreData) });
    } catch (err) {
      this.error = err; // preserve full Error object
    }
  }

  <template>
    {{#if this.hasError}}
