```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

// ❌ Option A — multiple booleans (impossible states possible)
class OptionAComponent extends Component {
  @tracked isIdle = true;
  @tracked isLoading = false;
  @tracked isSuccess = false;
  @tracked isError = false;
  // Bug risk: isLoading and isError both true simultaneously
}

// ✅ Option B — single status enum string (finite state machine)
export default class MatchFetcherComponent extends Component {
  @tracked status = 'idle';

  get isIdle()    { return this.status === 'idle'; }
  get isLoading() { return this.status === 'loading'; }
  get isSuccess() { return this.status === 'success'; }
  get isError()   { return this.status === 'error'; }

  @action async loadMatch(id) {
    this.status = 'loading';
    try {
      await fetch(`/api/matches/${id}`);
      this.status = 'success';
    } catch {
      this.status = 'error';
    }
  }

  <template>
    {{#if this.isLoading}}<p>Loading...</p>{{/if}}
    {{#if this.isSuccess}}<p>Loaded!</p>{{/if}}
    {{#if this.isError}}<p>Error</p>{{/if}}
  </template>
}
```
Multiple boolean flags allow impossible states — `isLoading` and `isError` both `true` simultaneously is a bug waiting to happen. A status string enum enforces mutual exclusivity at the data model level: only one string value can be stored at a time. Boolean getters derived from the string give you clean template expressions (`{{if this.isLoading}}`) without the state management risk. This pattern mirrors the XState / finite state machine mental model and is the industry-standard approach for async state in any framework.

