import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

// Option A — bind to Ember Data record directly
// ❌ Risk: mutations affect the record before save, polluting the store
// <input value={{@player.name}} {{on "input" (fn (mut @player.name))}} />

// Option B — @tracked draft copy (✅ Recommended)
export default class PlayerEditFormComponent extends Component {
  @tracked draftName = this.args.player.name;
  @tracked draftRuns = this.args.player.runs;

  @action
  async save() {
    this.args.player.name = this.draftName; // commit only on save
    this.args.player.runs = this.draftRuns;
    await this.args.player.save();
  }

  @action cancel() {
    this.draftName = this.args.player.name; // restore from record
    this.draftRuns = this.args.player.runs;
  }

  <template>
    <input value={{this.draftName}} {{on "input" (fn (mut this "draftName"))}} />
    <button {{on "click" this.save}}>Save</button>
    <button {{on "click" this.cancel}}>Cancel</button>
  </template>
}
```
