// Option B — single @tracked errors object (✅ Recommended for multi-field forms)
export default class PlayerFormComponent extends Component {
  @tracked playerName = '';
  @tracked runs = '';
  @tracked errors = {};

  @action
  validate() {
    const errors = {};
    if (!this.playerName.trim()) errors.playerName = 'Name is required';
    if (isNaN(Number(this.runs))) errors.runs = 'Runs must be a number';
    this.errors = errors; // replace entire object — reactive
    return Object.keys(errors).length === 0;
  }

  @action async submit() {
    if (!this.validate()) return;
    await this.args.onSubmit({ name: this.playerName, runs: Number(this.runs) });
  }

  <template>
    <input value={{this.playerName}} {{on "input" (fn (mut this "playerName"))}} />
    {{#if this.errors.playerName}}<p class="text-red-500">{{this.errors.playerName}}</p>{{/if}}
  </template>
}
```
A single `@tracked errors` object scales linearly — adding a new field requires one line in the validate function, not a new `@tracked` property. Replacing the entire errors object on each validation run is safe because the object is always small. Individual `@tracked` strings are acceptable for forms with 2–3 fields but become unwieldy beyond that. The errors object also enables bulk operations like `Object.keys(this.errors).length === 0` for overall form validity without counting individual boolean flags.

