import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

// Option A — store full objects (❌ memory heavy, stale reference risk)
class OptionAComponent extends Component {
  @tracked selectedPlayers = [];
  @action toggle(player) {
    const exists = this.selectedPlayers.find(p => p.id === player.id);
    this.selectedPlayers = exists
      ? this.selectedPlayers.filter(p => p.id !== player.id)
      : [...this.selectedPlayers, player]; // ❌ holds stale object if source updates
  }
}

// Option B — store ids only (✅ Recommended)
