```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

// Optimistic update (✅ Recommended for high-frequency, low-risk actions)
export default class LikeButtonComponent extends Component {
  @tracked isLiked = this.args.isLiked;
  @tracked count = this.args.likeCount;

  @action
  async toggleLike() {
    const wasLiked = this.isLiked;
    // Update UI immediately
    this.isLiked = !wasLiked;
    this.count += wasLiked ? -1 : 1;
    try {
      await fetch(`/api/players/${this.args.playerId}/like`, { method: 'POST' });
    } catch {
      // Revert on failure
      this.isLiked = wasLiked;
      this.count += wasLiked ? 1 : -1;
    }
  }

  <template>
    <button {{on "click" this.toggleLike}}>
      {{if this.isLiked "Unlike" "Like"}} ({{this.count}})
    </button>
  </template>
}
```
Use optimistic updates for low-risk, reversible actions (likes, bookmarks, toggles) where failure is rare and the instant feedback significantly improves perceived performance. Store the previous state before mutating `@tracked`, and revert in the catch block on failure. Use pessimistic updates (wait for API) for high-stakes operations (payments, score submissions, destructive deletions) where showing incorrect state even briefly is unacceptable. Always provide visual feedback during pessimistic waits to avoid the UI appearing frozen.

