import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';
import { task, timeout } from 'ember-concurrency';

// Option A — manual debounce (❌ verbose, timer cleanup needed)
class OptionAComponent extends Component {
  @tracked query = '';
  #timer = null;

  @action onInput(e) {
    this.query = e.target.value;
    clearTimeout(this.#timer);
    this.#timer = setTimeout(() => this.#fetchResults(), 300);
  }

  willDestroy() { super.willDestroy(); clearTimeout(this.#timer); }
}

// Option B — ember-concurrency restartable task (✅ Recommended)
export default class PlayerSearchComponent extends Component {
  @tracked query = '';

  searchTask = task(this, { restartable: true }, async () => {
    await timeout(300); // cancelled and restarted on each keystroke
    const res = await fetch(`/api/players?q=${this.query}`);
    return res.json();
  });

  @action
  onInput(e) {
    this.query = e.target.value;
    this.searchTask.perform();
  }

  <template>
    <input value={{this.query}} {{on "input" this.onInput}} />
    {{#if this.searchTask.isRunning}}<p>Searching...</p>{{/if}}
    {{#each this.searchTask.last.value as |p|}}<p>{{p.name}}</p>{{/each}}
  </template>
}
```
Use ember-concurrency `restartable` task for debounced search. It automatically cancels the previous task instance when a new one starts, eliminating race conditions where out-of-order responses overwrite correct results. It also provides `isRunning` for loading state, cleans up automatically on component destroy, and is fully testable with `waitForProperty`. Manual `setTimeout` debounce requires tracking the timer ID, manual cleanup in `willDestroy`, and separate loading state — all boilerplate that ember-concurrency eliminates.

