import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

// Option A — @tracked page number (offset pagination)
export default class MatchFeedOffsetComponent extends Component {
  @tracked matches = [];
  @tracked page = 1;
  @tracked hasMore = true;

  @action async loadMore() {
    const res = await fetch(`/api/matches?page=${this.page}&per=20`);
    const data = await res.json();
    this.matches = [...this.matches, ...data.matches];
    this.hasMore = data.hasNextPage;
    this.page += 1;
  }
}

// Option B — cursor-based (✅ Recommended for live data)
export default class MatchFeedCursorComponent extends Component {
  @tracked matches = [];
  @tracked cursor = null;
  @tracked hasMore = true;

  @action async loadMore() {
    const url = this.cursor ? `/api/matches?after=${this.cursor}` : '/api/matches';
    const res = await fetch(url);
    const data = await res.json();
    this.matches = [...this.matches, ...data.matches];
    this.cursor = data.nextCursor;
    this.hasMore = Boolean(data.nextCursor);
  }
}
```
Use cursor-based pagination for infinite scroll on live data (match feeds, commentary). Offset pagination (`?page=3`) is unstable when new items are inserted — a new match added to page 1 pushes everything down, causing page 3 to repeat items from page 2. Cursors reference a specific item, so insertions do not affect the next page. Use offset pagination only for static datasets (historical stats, archived matches) or when the backend does not support cursors.

