```
The current user is global application state — it must always live in a service. Components are destroyed and recreated on navigation; a service is a singleton that persists for the app session. Multiple components (header, dashboard, settings) read the current user simultaneously — a service with `@tracked currentUser` means a single update (login, profile change) reactively updates all of them. Never fetch or store current user in a component.

```gjs
// Option A — @action with global listener setup in component (manageable for 1–2 shortcuts)
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class ScoreboardComponent extends Component {
  @tracked score = 0;

  @action handleKeydown(e) {
    if (e.key === 'r') this.score += 1;
    if (e.key === 'Escape') this.score = 0;
  }

  constructor(owner, args) {
    super(owner, args);
    document.addEventListener('keydown', this.handleKeydown);
  }

  willDestroy() {
    super.willDestroy();
    document.removeEventListener('keydown', this.handleKeydown);
  }

  <template><p>Score: {{this.score}}</p></template>
}

// Option B — Ember modifier (✅ Recommended for reusable, composable keyboard bindings)
// {{keyboard-shortcut key="r" onPress=this.addRun}}
// Modifier encapsulates addEventListener/removeEventListener lifecycle
```
