```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchEditFormComponent extends Component {
  #savedData = { venue: this.args.match.venue };
  @tracked venue = this.args.match.venue;

  get isDirty() { return this.venue !== this.#savedData.venue; }

  constructor(owner, args) {
    super(owner, args);
    this.#beforeunload = (e) => {
      if (this.isDirty) { e.preventDefault(); }
    };
    window.addEventListener('beforeunload', this.#beforeunload);
  }

  willDestroy() {
    super.willDestroy();
    window.removeEventListener('beforeunload', this.#beforeunload);
  }

  // Also use isDirty in-app for Ember route transition warnings
  // Route.on('routeWillChange') or willTransition hook

  <template>
    <input value={{this.venue}} {{on "input" (fn (mut this "venue"))}} />
    {{#if this.isDirty}}<p class="text-orange-500">Unsaved changes</p>{{/if}}
  </template>
}
```
Use both together. `@tracked isDirty` (derived from a snapshot comparison) enables in-app UX: showing an "unsaved changes" indicator, disabling navigation within the Ember app, and conditionally enabling the save button. `beforeunload` catches browser-level navigation (closing the tab, refreshing). `beforeunload` alone cannot block Ember router transitions — you need `isDirty` with a route `willTransition` check. Neither alone is sufficient; combine them for complete protection.

