```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class RefreshScoreComponent extends Component {
  @tracked isRateLimited = false;
  @tracked callCount = 0;
  static MAX_CALLS_PER_MINUTE = 10;
  #windowStart = Date.now();

  @action
  async refreshScore() {
    const now = Date.now();
    if (now - this.#windowStart > 60000) {
      this.callCount = 0;
      this.#windowStart = now;
    }
    if (this.callCount >= RefreshScoreComponent.MAX_CALLS_PER_MINUTE) {
      this.isRateLimited = true;
      return;
    }
    this.callCount += 1;
    this.isRateLimited = false;
    await fetch('/api/score/refresh');
  }

  <template>
    <button disabled={{this.isRateLimited}} {{on "click" this.refreshScore}}>Refresh</button>
    {{#if this.isRateLimited}}<p class="text-red-500">Too many requests, please wait.</p>{{/if}}
  </template>
}
```
Add client-side `@tracked` rate limiting for UI actions that users might spam (refresh buttons, search-as-you-type). Client-side limiting disables the button before hitting the server, providing instant feedback and preventing wasted requests. Always keep server-side rate limiting as well — client-side limits can be bypassed. Use the combined approach: `@tracked isRateLimited` for immediate UX feedback, server 429 handling for security. Never rely solely on client-side rate limiting for security-sensitive endpoints.

