```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

// ❌ Before — four boolean flags, impossible states possible
class BrokenComponent extends Component {
  @tracked isIdle = true;
  @tracked isLoading = false;
  @tracked isError = false;
  @tracked isSuccess = false;
  // isLoading and isError both true? Nothing prevents this.
}

// ✅ After — single status string (finite state machine)
export default class MatchLoaderComponent extends Component {
  @tracked status = 'idle'; // exactly one of: 'idle'|'loading'|'success'|'error'
  @tracked errorMessage = '';

  get isIdle()    { return this.status === 'idle'; }
  get isLoading() { return this.status === 'loading'; }
  get isSuccess() { return this.status === 'success'; }
  get isError()   { return this.status === 'error'; }

  @action async fetchMatch(id) {
    this.status = 'loading';
    try {
      await fetch(`/api/matches/${id}`);
      this.status = 'success';
    } catch (e) {
      this.errorMessage = e.message;
      this.status = 'error';
    }
  }

  <template>
    {{#if this.isLoading}}<p>Loading...</p>{{/if}}
    {{#if this.isError}}<p>{{this.errorMessage}}</p>{{/if}}
  </template>
}
```
Refactor multiple async boolean flags into a single `@tracked status` string. The string acts as a finite state machine — only one state is active at any time by construction. Boolean getters derived from the string give clean template conditionals. This pattern eliminates impossible states (e.g., `isLoading && isError`), reduces the number of `@tracked` properties from four to one, and makes transitions explicit and auditable in the `@action`.

