import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';
import { task, timeout } from 'ember-concurrency';

// Option A — manual @tracked retry (❌ verbose, race-condition prone)
class ManualRetryComponent extends Component {
  @tracked retryCount = 0;
  @tracked isLoading = false;

  @action async fetchWithRetry(id) {
    this.isLoading = true;
    while (this.retryCount < 3) {
      try {
        await fetch(`/api/matches/${id}`);
        this.retryCount = 0;
        break;
      } catch {
        this.retryCount++;
        await new Promise(r => setTimeout(r, 1000 * this.retryCount));
      }
    }
    this.isLoading = false;
  }
}

// Option B — ember-concurrency with retry loop (✅ Recommended)
export default class MatchFetcherComponent extends Component {
  @tracked attempts = 0;

  fetchMatch = task(this, { drop: true }, async (matchId) => {
    for (let i = 1; i <= 3; i++) {
      try {
        const res = await fetch(`/api/matches/${matchId}`);
        this.attempts = 0;
        return res.json();
      } catch {
        this.attempts = i;
        await timeout(1000 * i); // exponential backoff
      }
    }
    throw new Error('Max retries reached');
  });

  <template>
    {{#if this.fetchMatch.isRunning}}
      <p>Attempt {{this.attempts}} of 3...</p>
    {{/if}}
    <button {{on "click" (fn this.fetchMatch.perform @matchId)}}>Load</button>
  </template>
}
```
Use ember-concurrency for retry loops. The task handles cancellation automatically (destroyed component, `drop` modifier), while manual `@tracked retryCount` with `while` loops can continue running after a component unmounts, causing asserted errors. Use `@tracked attempts` only to display the current attempt number in the template — let the task control the loop logic. ember-concurrency's `timeout` is also test-friendly, accepting fake timers in test environments.

