// Option A — @tracked in component (✅ for simple single-page tours)
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class ScorecardTourComponent extends Component {
  @tracked step = 0;
  steps = [
    { target: '.runs-display', text: 'This shows live runs' },
    { target: '.wickets-display', text: 'And current wickets' },
  ];

  get currentStep() { return this.steps[this.step]; }
  get isLastStep() { return this.step === this.steps.length - 1; }

  @action next() { this.step += 1; }
  @action finish() { this.args.onComplete?.(); }

  <template>
    {{#if this.currentStep}}
      <div class="absolute bg-blue-800 text-white p-3 rounded">
        {{this.currentStep.text}}
        <button {{on "click" (if this.isLastStep this.finish this.next)}}>
          {{if this.isLastStep "Done" "Next"}}
        </button>
      </div>
    {{/if}}
  </template>
}

// Option B — onboarding service (✅ for multi-route tours spanning navigation)
// Tracks step across route changes, persists completion to localStorage
```
Use `@tracked step` in the component for single-page tours confined to one route — it is simple, self-contained, and discarded when the tour component unmounts. Use an onboarding service when the tour spans multiple routes (step 1 on `/matches`, step 2 on `/players`), when completion status must persist to `localStorage` to prevent reshowing, or when multiple components across the page need to react to the current tour step (e.g., highlighting different elements).

