// Option B — ember-concurrency looping task (✅ Recommended)
import Component from '@glimmer/component';
import { task, timeout } from 'ember-concurrency';

export default class LiveScorePollerComponent extends Component {
  pollScore = task(this, { on: 'init' }, async () => {
    while (true) {
      const res = await fetch('/api/live-score');
      // store result in service or @tracked
      await timeout(30000);
    }
  });

  // Task is automatically cancelled when component is destroyed
  // No willDestroy cleanup needed
  // In tests: controlledClock.tick(30000) advances the timeout

