```gjs
// ✅ CORRECT — use getter for reactive args access
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class ChaseTrackerComponent extends Component {
  @tracked runs = 0;

  get isWon() {
    return this.runs >= this.args.targetScore;
  }

  @action
  addRuns(n) {
    this.runs += n;
    // check isWon via the getter, not inline
  }
}
```

Getters re-execute on every render and always read the current value of `this.args`. An `@action`, however, executes at a point in time — if the parent has re-rendered and changed `@args` between renders, the action may capture an outdated value. For reactive derivations based on args, always use a getter.

```gjs
// ❌ WRONG
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class ScoreDisplayComponent extends Component {
