import { tracked } from '@glimmer/tracking';

export default class LiveScoreComponent extends Component {
  @tracked isActive = true;
  _isDestroyed = false; // plain flag for internal cleanup logic

  willDestroy() {
    super.willDestroy();
    this._isDestroyed = true; // safe — not tracked, no re-render triggered
