import { tracked } from '@glimmer/tracking';

export default class StatsComponent extends Component {
  @tracked rawScore = 150;

  get score() { return this.rawScore; }        // pointless wrapper
  get displayScore() { return this.score; }    // pointless wrapper
  get formattedScore() { return `${this.displayScore} runs`; } // could read rawScore directly
}
```

```gjs
// ✅ CORRECT — direct, minimal getter chain
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class StatsComponent extends Component {
  @tracked rawScore = 150;

  get formattedScore() {
    return `${this.rawScore} runs`; // reads tracked source directly
  }
}
```

Each extra getter in a chain adds an indirection that Glimmer must walk when tracking dependencies. It also makes the code harder to follow. If a getter adds no logic — it just re-exposes another getter or the tracked field directly — remove it and have downstream consumers read the source directly.

```gjs
// ❌ WRONG — modifying tracked state during render
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class ScoreComponent extends Component {
  @tracked score = 0;

  get currentScore() {
    this.score += 1; // ❌ side effect inside getter — mutates during render
    return this.score;
  }

  <template>
    <p>{{this.currentScore}}</p>
  </template>
}
```

```gjs
// ✅ CORRECT — getters must be pure; mutations only in @action
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';
import { on } from '@ember/modifier';

export default class ScoreComponent extends Component {
  @tracked score = 0;

  get currentScore() {
    return this.score; // pure — no side effects
  }

  @action
  incrementScore() {
    this.score += 1;
  }

  <template>
    <p>{{this.currentScore}}</p>
    <button {{on "click" this.incrementScore}}>+1</button>
  </template>
}
```

Glimmer getters are called during the render phase and must be pure — they should only compute and return a value. Mutating `@tracked` state inside a getter causes a re-render during a render, which Glimmer detects and throws a 'backtracking re-render' assertion to prevent an infinite loop. Always keep mutations in `@action` methods, never in getters.

```gjs
// ❌ WRONG — parent component
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class MatchComponent extends Component {
  @tracked totalRuns = 0;

  recordRun(runs) { // ❌ no @action — unbound method
    this.totalRuns += runs; // 'this' is undefined when called from child
  }

  <template>
    <ScoreInput @onScore={{this.recordRun}} />
  </template>
}
```

```gjs
// ✅ CORRECT
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchComponent extends Component {
  @tracked totalRuns = 0;

  @action
  recordRun(runs) { // bound — 'this' is always the component instance
    this.totalRuns += runs;
  }

  <template>
    <ScoreInput @onScore={{this.recordRun}} />
  </template>
}
```

When a method is passed to a child component as a named argument and the child calls it, the method loses its `this` binding unless it has been bound to the instance. `@action` performs this binding automatically, ensuring that `this` inside the method always refers to the parent component instance regardless of how or where the function is called.

```gjs
// ❌ WRONG
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { on } from '@ember/modifier';

export default class RunComponent extends Component {
  @tracked runs = 0;

  addRun() {
    this.runs += 4;
  }

  <template>
    {{!-- ❌ .bind(this) creates a new function on every render --}}
    <button {{on "click" (fn this.addRun.bind this)}}>+4 Runs</button>
  </template>
}
```

```gjs
// ✅ CORRECT
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';
import { on } from '@ember/modifier';

export default class RunComponent extends Component {
  @tracked runs = 0;

  @action
  addRun() {
    this.runs += 4;
  }

  <template>
    <button {{on "click" this.addRun}}>+4 Runs</button>
  </template>
}
```

Calling `.bind(this)` in the template creates a brand new function object on every render cycle. This causes the `{{on}}` modifier to remove and re-add the event listener on every render, which is wasteful and can cause subtle bugs. `@action` binds `this` once at class definition time, so the same bound function reference is reused across renders.

```gjs
// ❌ BAD PRACTICE — works but creates new function on every render
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { on } from '@ember/modifier';

export default class BallTrackerComponent extends Component {
  @tracked balls = [];
  ball = { runs: 4, type: 'boundary' };

  recordBall(ball) {
    this.balls = [...this.balls, ball];
  }

  <template>
    {{!-- inline arrow = new function every render --}}
    <button {{on "click" (fn () => this.recordBall this.ball)}}>Record Ball</button>
  </template>
}
```

```gjs
// ✅ CORRECT — use @action + fn helper
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';
import { on } from '@ember/modifier';
import { fn } from '@ember/helper';

export default class BallTrackerComponent extends Component {
  @tracked balls = [];
  ball = { runs: 4, type: 'boundary' };

  @action
  recordBall(ball) {
    this.balls = [...this.balls, ball];
  }

  <template>
    <button {{on "click" (fn this.recordBall this.ball)}}>Record Ball</button>
  </template>
}
```

Inline arrow functions in templates allocate a new function object on every render, causing the `{{on}}` modifier to tear down and re-register the event listener unnecessarily. Use `@action` for the method definition and the `{{fn}}` helper to partially apply arguments — this passes a stable function reference that doesn't change between renders.

```gjs
// ❌ WRONG
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class MatchComponent extends Component {
  @tracked args = {}; // ❌ 'args' is already defined on @glimmer/component!

  get homeTeam() {
    return this.args.homeTeam; // now reads the local @tracked, not real args
  }
}
```

```gjs
// ✅ CORRECT — never shadow built-in component properties
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class MatchComponent extends Component {
  @tracked localState = {}; // use a different, non-conflicting name

  get homeTeam() {
    return this.args.homeTeam; // reads the real Glimmer args proxy
  }
}
```

`@glimmer/component` defines several built-in properties on the component prototype including `args`, `isDestroying`, and `isDestroyed`. Declaring a `@tracked` property with the same name shadows the inherited property, breaking core Glimmer functionality. Always check the `@glimmer/component` API before naming tracked properties.

```gjs
// ❌ WRONG — stale closure
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class OverTrackerComponent extends Component {
  @tracked over = 1;

  @action
  fetchOverData() {
    const currentOver = this.over; // captured at call time
    fetch(`/api/over/${currentOver}`)
      .then(r => r.json())
      .then(data => {
        // ❌ if this.over changed while fetching, currentOver is stale
        console.log(`Data for over ${currentOver}:`, data);
      });
  }
}
```

```gjs
// ✅ CORRECT — use ember-concurrency task to safely handle async state
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { task } from 'ember-concurrency';

export default class OverTrackerComponent extends Component {
  @tracked over = 1;

  fetchOverData = task(async () => {
    const over = this.over; // read at task start — document this intent
    const data = await fetch(`/api/over/${over}`).then(r => r.json());
    // task is cancelled if component destroys or task is restarted
    console.log(`Data for over ${over}:`, data);
  });
}
```

A Promise `.then()` callback closes over values at the time the Promise is created. If `@tracked` state changes between creating the Promise and the callback executing, the callback operates on the old captured value. `ember-concurrency` tasks with `restartable` policy can be used to cancel in-flight requests and start fresh with the latest state.

```gjs
// ❌ WRONG — duplicating args into tracked state
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class MatchCardComponent extends Component {
  @tracked match; // will be stale when parent updates @match arg

  constructor(owner, args) {
    super(owner, args);
    this.match = args.match; // snapshot — won't react to future arg changes
