import Component from '@glimmer/component';

export default class MatchCardComponent extends Component {
  <template>
    <p>{{@match.team}}</p>
  </template>
}
```

Data that originates from the parent and is passed as an argument (`@arg`) should be read directly from `this.args` or `@argName` in the template. Copying it into a `@tracked` property creates a local snapshot that becomes stale the moment the parent updates the argument. Only use `@tracked` for state that the component itself manages and mutates.

```gjs
// ❌ WRONG
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchLoaderComponent extends Component {
  @tracked matchData = null;
  @tracked isLoading = false;

  @action
  async loadMatch() {
    this.isLoading = true;
    const response = fetch('/api/match/1'); // ❌ forgot await — response is a Promise
    this.matchData = response.json();        // ❌ calling .json() on a Promise, not Response
    this.isLoading = false;
