```gjs
// ✅ CORRECT
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchLoaderComponent extends Component {
  @tracked matchData = null;
  @tracked isLoading = false;

  @action
  async loadMatch() {
    this.isLoading = true;
    try {
      const response = await fetch('/api/match/1');
      this.matchData = await response.json();
    } finally {
      this.isLoading = false;
    }
  }
}
```

Without `await`, `fetch()` returns a `Promise<Response>` rather than a resolved `Response`. Calling `.json()` on a Promise object (not a Response) returns `undefined` or throws, and `this.matchData` is set to a pending Promise or nothing useful. Always `await` async operations inside `async @action` methods.

```gjs
// ❌ POTENTIALLY WRONG (works but discouraged — relies on implicit read+write)
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class ScoreCounterComponent extends Component {
