```gjs
// ✅ CORRECT — use structuredClone
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchEditorComponent extends Component {
  @tracked match = { team: 'India', score: 0, date: new Date() };

  @action
  resetMatch() {
    this.match = structuredClone(this.match); // ✅ handles Date, Map, Set, etc.
  }
}
```

`JSON.parse(JSON.stringify())` is slow for large objects and silently drops or corrupts non-JSON-serialisable values like `Date`, `undefined`, `Map`, `Set`, and class instances. `structuredClone()` is a native browser/Node API that performs a true deep clone while correctly handling these types. Use it for deep copying state in `@action` methods.

```gjs
// ❌ WRONG — shallow copy: nested array is still shared
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class TeamEditorComponent extends Component {
  @tracked team = { name: 'India', players: ['Rohit', 'Virat'] };

  @action
  editTeam() {
    const draft = { ...this.team }; // ❌ shallow — draft.players === this.team.players
    draft.players.push('Gill');     // mutates the ORIGINAL team.players array!
    this.team = draft;
  }
}
```

```gjs
// ✅ CORRECT — deep clone with structuredClone
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class TeamEditorComponent extends Component {
  @tracked team = { name: 'India', players: ['Rohit', 'Virat'] };

  @action
  editTeam() {
    const draft = structuredClone(this.team); // ✅ deep clone — nested array is new
    draft.players.push('Gill');
    this.team = draft;
  }
}
```

Object spread (`{ ...obj }`) only copies the top level of an object — nested arrays and objects are still shared references. Mutating a nested value in the copy also mutates the original, which can cause unexpected template behaviour and makes state history tracking impossible. Use `structuredClone()` when you need a fully independent deep copy.

```gjs
