```gjs
// ✅ CORRECT — deduplicate by player id before adding
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class TeamBuilderComponent extends Component {
  @tracked selectedPlayers = [];

  @action
  addPlayer(player) {
    const alreadyAdded = this.selectedPlayers.some(p => p.id === player.id);
    if (!alreadyAdded) {
      this.selectedPlayers = [...this.selectedPlayers, player];
    }
  }
}
```

Array spread does not deduplicate — it simply appends the new item regardless of whether it already exists. Use `Array.prototype.some()` to check for an existing entry by a stable identifier (`player.id`) before appending. This guards the tracked array against duplicates caused by rapid clicks, network retries, or accidental repeated invocations.

