import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

const STATUS = Object.freeze({ IDLE: 'idle', LOADING: 'loading', SUCCESS: 'success', ERROR: 'error' });

export default class MatchStatusComponent extends Component {
  @tracked status = STATUS.IDLE;

