  get minutesUntilStart() {
    const now = Date.now(); // ❌ not tracked — Glimmer doesn't know time changed
    const diff = this.matchStartTime.getTime() - now;
    return Math.max(0, Math.floor(diff / 60000));
  }
  // getter only re-runs when matchStartTime changes — not every second
