```gjs
// ✅ CORRECT — store 'now' in @tracked, update via interval
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class CountdownComponent extends Component {
  @tracked matchStartTime = new Date('2024-12-01T10:00:00');
  @tracked now = Date.now(); // ✅ tracked — updates trigger re-render

  #interval = null;

  constructor(owner, args) {
    super(owner, args);
    this.#interval = setInterval(() => { this.now = Date.now(); }, 1000);
  }

  willDestroy() {
    super.willDestroy();
    clearInterval(this.#interval);
  }

  get minutesUntilStart() {
    const diff = this.matchStartTime.getTime() - this.now;
    return Math.max(0, Math.floor(diff / 60000));
  }
}
```

Glimmer only recomputes a getter when one of its `@tracked` dependencies changes. `Date.now()` is a plain function call with no tracking — reading it inside a getter does not register it as a dependency. To create a time-reactive getter, store the current timestamp in a `@tracked now` property and update it via a `setInterval`, so each tick triggers a tracked assignment and thus a re-render.

