// ✅ CORRECT — clamp index to valid range in getter
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class TabBarComponent extends Component {
  @tracked activeTabIndex = 0;

  get safeTabIndex() {
    return Math.min(this.activeTabIndex, this.args.tabs.length - 1);
  }

  get activeTab() {
    return this.args.tabs[this.safeTabIndex] ?? null;
  }

  @action
  setTab(index) {
    this.activeTabIndex = index;
  }
}
```

When the parent passes a shorter list of tabs, a previously valid `activeTabIndex` may exceed the new array bounds, causing `undefined` access in the getter and a rendering crash. Use `Math.min()` in a `safeTabIndex` getter to clamp the tracked index to the valid range, ensuring the component degrades gracefully when the tab list shrinks.

