```gjs
// ✅ CORRECT — Object.assign into a NEW empty object, then assign
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchEditorComponent extends Component {
  @tracked match = { team: 'India', score: 0 };

  @action
  updateScore(runs) {
    this.match = Object.assign({}, this.match, { score: this.match.score + runs });
    // ✅ new object reference — or use spread: { ...this.match, score: ... }
  }
